// Fresh-row response. Surface the persisted, redacted row, not the raw model output.
const persisted = $('Create Verification Record').first().json.result.verification;
const verdict = $('Parse + Validate Verdict').first().json.verdict;
return [{ json: {
  ok: true,
  verification_id: persisted.id,
  status: persisted.status,
  version: persisted.version,
  reviewer: persisted.reviewer,
  codex_status: persisted.codex_status,
  findings: persisted.findings || [],
  summary: persisted.summary || null,
  criteria_checked: verdict.criteria_checked || [],
  criteria_unverifiable: verdict.criteria_unverifiable || [],
  validation_issues: verdict.validation_issues || [],
  replayed: false
}}];

// codex F-003 hardening: get_latest returns ONLY the minimal projection (id, status,
// codex_status, version, timestamps, finding count) by default. The full row (findings,
// summary, evidence) is gated behind the codex-run token — only operators and the codex
// worker who hold APEX_CODEX_RUN_TOKEN see substantive content. PM Agent uses the minimal
// projection to decide whether to advance a task (status + codex_status is sufficient).
const row = $json.verification;
if (!row) return [{ json: { ok: true, verification_id: null, status: 'not_found' } }];
const headers = $('Webhook').first().json.headers || {};
const rawRunToken = headers['x-apex-codex-run-token'] || headers['X-Apex-Codex-Run-Token'];
const RUN_TOKEN_ENV = ($env && $env.APEX_CODEX_RUN_TOKEN) || '';
const privileged = RUN_TOKEN_ENV.length > 0 && rawRunToken && String(rawRunToken) === RUN_TOKEN_ENV;
const findingsArr = Array.isArray(row.findings) ? row.findings : [];
const minimal = {
  ok: true,
  verification_id: row.id,
  status: row.status,
  codex_status: row.codex_status,
  version: row.version,
  finding_count: findingsArr.length,
  created_at: row.created_at,
  updated_at: row.updated_at
};
if (privileged) {
  return [{ json: { ...minimal, verification: row, summary: row.summary || null, findings: findingsArr } }];
}
return [{ json: minimal }];

// codex F-007/F-014 hardening: same expanded pattern set used in Build Prompt and Parse
// + Validate Verdict — single source of truth for redaction across all persistence sinks.
const input = $json;
const PRE_REDACT_PATTERNS = [
  /AKIA[0-9A-Z]{16}/g,
  /ASIA[0-9A-Z]{16}/g,
  /sk-[A-Za-z0-9]{20,}/g,
  /sk-ant-[A-Za-z0-9_-]{20,}/g,
  /xox[baprs]-[A-Za-z0-9-]{10,}/g,
  /ghp_[A-Za-z0-9]{20,}/g,
  /github_pat_[A-Za-z0-9_]{20,}/g,
  /gho_[A-Za-z0-9]{20,}/g,
  /npm_[A-Za-z0-9]{20,}/g,
  /Bearer\s+[A-Za-z0-9_\-\.]{20,}/gi,
  /eyJ[A-Za-z0-9_-]{10,}\.eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}/g,
  /-----BEGIN [A-Z ]+PRIVATE KEY-----[\s\S]*?-----END [A-Z ]+PRIVATE KEY-----/g,
  /-----BEGIN OPENSSH PRIVATE KEY-----[\s\S]*?-----END OPENSSH PRIVATE KEY-----/g,
  /(postgres(ql)?|mysql|mongodb(\+srv)?|redis|amqp):\/\/[^\s:\/@]+:[^\s@]+@[^\s\/?#]+/gi,
  /\d{3}-\d{2}-\d{4}/g,
  /[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/g,
  /\+?\d{1,3}[\s.-]?\(?\d{2,4}\)?[\s.-]?\d{3,4}[\s.-]?\d{3,4}/g
];
function redact(s) {
  if (s == null || typeof s !== 'string') return s;
  let out = s;
  for (const p of PRE_REDACT_PATTERNS) out = out.replace(p, '[REDACTED]');
  return out;
}
const findings = (input.codex_findings || []).map((f, idx) => ({
  id: redact(typeof f.id === 'string' ? f.id : `CDX-${String(idx+1).padStart(3,'0')}`),
  severity: f.severity || 'info',
  summary: redact(f.summary || ''),
  criterion_id: redact(f.criterion_id || null),
  evidence: redact(f.evidence || ''),
  recommendation: redact(f.recommendation || '')
}));
return [{ json: {
  ...input,
  codex_findings_redacted: findings,
  summary_append_redacted: redact(input.summary_append || null)
}}];

const result = $json.result;
if (!result) {
  return [{ json: { __rpc_error: { ok: false, error: 'db_unavailable', detail: 'update_verification_codex_outcome returned no result', http_status: 503 } } }];
}
if (result.error) {
  const map = {
    invalid_codex_status: 422,
    invalid_status_override: 422,
    findings_not_array: 422,
    verification_not_found: 404,
    codex_pipeline_terminal: 409
  };
  return [{ json: { __rpc_error: { ok: false, error: result.error, detail: result.current || result.detail || null, http_status: map[result.error] || 422 } } }];
}
return [{ json: { rpc_ok: true, result } }];
